import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, Outlet } from 'react-router-dom';

// -- CÁC COMPONENT CỐT LÕI --
import Sidebar from './components/Sidebar';
import LoginPage from './pages/LoginPage';
import LogoutPage from './pages/LogoutPage';
import Dashboard from './pages/Dashboard';

// -- CÁC COMPONENT QUẢN LÝ BAN ĐẦU --
import UserListPage from './pages/UserListPage';
import CustomerListPage from './pages/CustomerListPage';
import KhaiBaoCoSo from './pages/KhaiBaoCoSo';

// -- CÁC COMPONENT CHỨC NĂNG MỚI ĐÃ THÊM --
import AddProductToFarm from './pages/AddProductToFarm';
import ProductManagementPage from './pages/ProductManagementPage';
import MasterProductListPage from './pages/MasterProductListPage';
import StatsReportPage from './pages/StatsReportPage';
import SubReportAPage from './pages/SubReportAPage';
import SubReportBPage from './pages/SubReportBPage';


function App() {
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  // Component Layout chung cho các trang cần đăng nhập và có Sidebar
  const ProtectedLayout = () => {
    // Nếu không có token, chuyển hướng về trang đăng nhập
    if (!token) {
      return <Navigate to="/" replace />;
    }
    // Nếu đã đăng nhập, hiển thị layout với Sidebar và nội dung trang
    return (
      <div style={{ display: 'flex' }}>
        <Sidebar />
        <main style={{ flex: 1, padding: '20px' }}>
          <Outlet /> {/* <Outlet/> sẽ là nơi render component của route con */}
        </main>
      </div>
    );
  };

  return (
    <Router>
      <Routes>
        {/* Route công khai, không cần đăng nhập */}
        <Route path="/" element={<LoginPage />} />

        {/* Bọc tất cả các route cần bảo vệ trong ProtectedLayout */}
        <Route element={<ProtectedLayout />}>

          {/* --- CÁC ROUTE CHÍNH --- */}
          <Route path="/dashboard" element={<Dashboard />} />
          <Route path="/khai-bao" element={<KhaiBaoCoSo />} />
          <Route path="/logout" element={<LogoutPage />} />

          {/* --- CÁC ROUTE QUẢN LÝ LÂM SẢN & CƠ SỞ --- */}
          <Route path="/manage-products/:farmId" element={<ProductManagementPage />} />
          <Route path="/farm/:farmId/add-product" element={<AddProductToFarm />} />

          {/* --- CÁC ROUTE BÁO CÁO & TỔNG HỢP --- */}
          <Route path="/bao-cao-tong-hop" element={<MasterProductListPage />} />
          <Route path="/stats-report" element={<StatsReportPage />}>
            <Route path="subA" element={<SubReportAPage />} />
            <Route path="subB" element={<SubReportBPage />} />
          </Route>

          {/* --- CÁC ROUTE CHỈ DÀNH CHO ADMIN --- */}
          {role === 'admin' && (
            <>
              <Route path="/admin/users" element={<UserListPage />} />
              <Route path="/admin/customers" element={<CustomerListPage />} />
            </>
          )}

        </Route>

        {/* Route mặc định nếu không tìm thấy đường dẫn */}
        <Route path="*" element={<div><h2>404 Not Found</h2><p>Trang bạn tìm kiếm không tồn tại.</p></div>} />
      </Routes>
    </Router>
  );
}

export default App;
